import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import BasicPage from './components/BasicPage';
import CVResume from './components/CVResume';
import './App.css';

function App() {
  return (
    <Router>
      <div className="App">
        <nav className="navigation">
          <div className="nav-container">
            <h2 className="nav-title">Hausaufgaben React</h2>
            <div className="nav-links">
              <Link to="/" className="nav-link">Basic Page</Link>
              <Link to="/cv" className="nav-link">CV Resume</Link>
            </div>
          </div>
        </nav>
        
        <main className="main-content">
          <Routes>
            <Route path="/" element={<BasicPage />} />
            <Route path="/cv" element={<CVResume />} />
          </Routes>
        </main>
        
        <footer className="footer">
          <p>&copy; 2024 Doga Ceren Bozkurt - React Portfolio</p>
        </footer>
      </div>
    </Router>
  );
}

export default App;
